/* ─────────────────────────────────────────────────────────────────
   API HELPER
───────────────────────────────────────────────────────────────── */
const API = "http://localhost:5000";

const api = async (path, options = {}) => {
  const token = localStorage.getItem("luxtech_token");
  const res = await fetch(`${API}${path}`, {
    headers: {
      "Content-Type": "application/json",
      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    },
    ...options,
  });
  return res.json();
};

/* ─────────────────────────────────────────────────────────────────
   APP
───────────────────────────────────────────────────────────────── */
export default function App() {
  const [page, setPage]       = useState("home");
  const [prod, setProd]       = useState(null);
  const [cart, setCart]       = useState([]);
  const [wish, setWish]       = useState([]);
  const [user, setUser]       = useState(null);
  const [orders, setOrders]   = useState([]);
  const [coupon, setCoupon]   = useState(null);
  const [searchQ, setSearchQ] = useState("");
  const [toast, setToast]     = useState("");
  const [apiOnline, setApiOnline] = useState(false);
  const tRef = useRef(null);

  // ── Check if backend is online ──────────────────────────────────
  useState(() => {
    fetch(`${API}/`)
      .then(r => r.json())
      .then(d => { if (d.success) setApiOnline(true); })
      .catch(() => setApiOnline(false));

    // Restore logged-in user from localStorage
    const saved = localStorage.getItem("luxtech_user");
    const token = localStorage.getItem("luxtech_token");
    if (saved && token) {
      setUser(JSON.parse(saved));
      // Fetch real orders
      api("/api/orders/my").then(d => { if (d.success) setOrders(d.orders); });
    }
  }, []);

  const showToast = msg => {
    setToast(msg);
    clearTimeout(tRef.current);
    tRef.current = setTimeout(() => setToast(""), 2600);
  };

  const nav = (p, pr = null) => {
    setPage(p);
    if (pr !== null) setProd(pr);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  // ── Cart (local state) ──────────────────────────────────────────
  const addToCart = (product, qty = 1) => {
    setCart(prev => {
      const ex = prev.find(i => i.id === product.id);
      return ex
        ? prev.map(i => i.id === product.id ? { ...i, qty: i.qty + qty } : i)
        : [...prev, { ...product, qty }];
    });
    showToast(`${product.name} added to cart ✦`);
  };
  const updateQty  = (id, d) => setCart(p => p.map(i => i.id === id ? { ...i, qty: Math.max(1, i.qty + d) } : i));
  const removeItem = id => { setCart(p => p.filter(i => i.id !== id)); showToast("Item removed"); };

  // ── Wishlist — real API if logged in, local if not ──────────────
  const toggleWish = async product => {
    if (user && apiOnline) {
      const d = await api(`/api/wishlist/${product.id}`, { method: "POST" });
      showToast(d.message);
      if (d.action === "added") setWish(p => [...p, product]);
      else setWish(p => p.filter(i => i.id !== product.id));
    } else {
      const has = wish.find(i => i.id === product.id);
      setWish(p => has ? p.filter(i => i.id !== product.id) : [...p, product]);
      showToast(has ? "Removed from wishlist" : "Added to wishlist ♥");
    }
  };

  // ── Login via real API ──────────────────────────────────────────
  const loginUser = async (email, password, name = null) => {
    if (!apiOnline) {
      // Fallback: mock login if backend offline
      const u = { name: name || "Guest User", email };
      setUser(u);
      showToast(`Welcome! ✦`);
      return { success: true };
    }
    const endpoint = name ? "/api/auth/register" : "/api/auth/login";
    const d = await api(endpoint, {
      method: "POST",
      body: JSON.stringify({ name, email, password }),
    });
    if (d.success) {
      localStorage.setItem("luxtech_token", d.token);
      localStorage.setItem("luxtech_user", JSON.stringify(d.user));
      setUser(d.user);
      showToast(d.message);
      // Load orders
      const od = await api("/api/orders/my");
      if (od.success) setOrders(od.orders);
    } else {
      showToast(d.message || "Login failed");
    }
    return d;
  };

  // ── Logout ──────────────────────────────────────────────────────
  const logoutUser = () => {
    localStorage.removeItem("luxtech_token");
    localStorage.removeItem("luxtech_user");
    setUser(null);
    setOrders([]);
    setWish([]);
    showToast("Signed out");
  };

  // ── Validate coupon via real API ────────────────────────────────
  const validateCoupon = async code => {
    if (!apiOnline) {
      const COUPONS_LOCAL = { LUXTECH20:{pct:20,label:"20% Off"}, SAVE10:{pct:10,label:"10% Off"}, NEWUSER15:{pct:15,label:"15% Off"} };
      return COUPONS_LOCAL[code.toUpperCase()] || null;
    }
    const d = await api("/api/wishlist/validate-coupon", { method:"POST", body:JSON.stringify({ code }) });
    return d.success ? d.coupon : null;
  };

  // ── Place order via real API ────────────────────────────────────
  const placeOrder = async (shipping_info, payment_method) => {
    if (!apiOnline || !user) {
      // Fallback mock
      const o = {
        id: `LT-2026-${Math.floor(Math.random()*900+100)}`,
        order_number: `LT-2026-${Math.floor(Math.random()*900+100)}`,
        date: new Date().toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}),
        items: cart.map(i => i.name),
        total, status: "Processing",
        tracking: "LTEX" + Math.floor(Math.random()*90000000+10000000),
      };
      setOrders(p => [o, ...p]);
      return { success: true, order: o };
    }
    const d = await api("/api/orders/checkout", {
      method: "POST",
      body: JSON.stringify({
        items: cart.map(i => ({ id:i.id, name:i.name, price:i.price, quantity:i.qty })),
        shipping: shipping_info,
        coupon_code: coupon?.code,
        payment_method,
      }),
    });
    if (d.success) {
      const od = await api("/api/orders/my");
      if (od.success) setOrders(od.orders);
    }
    return d;
  };

  const subtotal  = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const discount  = coupon ? Math.round(subtotal * coupon.pct / 100) : 0;
  const shipping  = subtotal > 999 ? 0 : 49;
  const total     = subtotal - discount + shipping;
  const cartCount = cart.reduce((s, i) => s + i.qty, 0);

  const sh = {
    nav, cart, wish, user, setUser, orders, setOrders, coupon, setCoupon,
    subtotal, discount, shipping, total, cartCount,
    addToCart, updateQty, removeItem, toggleWish,
    searchQ, setSearchQ, showToast,
    loginUser, logoutUser, validateCoupon, placeOrder,
    apiOnline, api,
  };

  return (
    <>
      <style>{FONTS + CSS}</style>
      {/* API status indicator */}
      <div style={{position:"fixed",bottom:8,right:12,fontSize:9,letterSpacing:2,textTransform:"uppercase",color:apiOnline?"var(--sc)":"var(--er)",zIndex:999,opacity:.7}}>
        {apiOnline ? "⚡ API Online" : "○ API Offline"}
      </div>
      <Navbar {...sh} page={page} />
      {page === "home"     && <HomePage     {...sh} />}
      {page === "shop"     && <ShopPage     {...sh} />}
      {page === "product"  && <ProductPage  {...sh} prod={prod} />}
      {page === "cart"     && <CartPage     {...sh} />}
      {page === "checkout" && <CheckoutPage {...sh} />}
      {page === "account"  && <AccountPage  {...sh} />}
      {page === "admin"    && <AdminPage    showToast={showToast} api={api} apiOnline={apiOnline} />}
      <Footer nav={nav} />
      <div className={`toast${toast ? " show" : ""}`}>{toast}</div>
    </>
  );
}

